import torch
import torch.nn as nn
import torch.nn.functional as F


class ConditionalVAE(nn.Module):
    """
    Class-conditional VAE.
    Encoder: q(z|x,c)  — image and label both go into the encoder.
    Decoder: p(x|z,c)  — label also goes into the decoder.
    At generation time, sample z ~ N(0,I) and pick a class c to control output.
    """
    def __init__(self, input_dim: int = 784, num_classes: int = 10,
                 h_dim: int = 256, latent_dim: int = 64):
        super().__init__()
        # One-hot class embedding
        self.latent_dim = latent_dim
        self.encoder = nn.Sequential(
            nn.Linear(input_dim + num_classes, h_dim), nn.ReLU(),
        )
        self.fc_mu = nn.Linear(h_dim, latent_dim)
        self.fc_lv = nn.Linear(h_dim, latent_dim)
        self.decoder = nn.Sequential(
            nn.Linear(latent_dim + num_classes, h_dim), nn.ReLU(),
            nn.Linear(h_dim, input_dim), nn.Sigmoid(),
        )
        self.num_classes = num_classes

    def one_hot(self, y: torch.Tensor) -> torch.Tensor:
        return F.one_hot(y, self.num_classes).float()

    def encode(self, x, y):
        c = self.one_hot(y)
        h = self.encoder(torch.cat([x, c], -1))
        return self.fc_mu(h), self.fc_lv(h)

    def decode(self, z, y):
        c = self.one_hot(y)
        return self.decoder(torch.cat([z, c], -1))

    def forward(self, x, y):
        mu, lv = self.encode(x, y)
        z = mu + torch.exp(0.5 * lv) * torch.randn_like(mu)
        x_hat = self.decode(z, y)
        recon = F.binary_cross_entropy(x_hat, x, reduction="sum") / x.size(0)
        kl = -0.5 * (1 + lv - mu.pow(2) - lv.exp()).sum(1).mean()
        return recon + kl, x_hat

    @torch.no_grad()
    def generate(self, y: torch.Tensor, device: torch.device):
        z = torch.randn(len(y), self.latent_dim, device=device)
        return self.decode(z, y.to(device))
